Here's how to handle each scenario with modern MSTest (3.9+):

```csharp
[TestClass]
public sealed class PlatformTests
{
    private readonly TestContext _testContext;
    private string? _tempFile;

    public PlatformTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    // 1. Windows-only (skipped on Linux/macOS)
    [TestMethod]
    [OSCondition(OperatingSystems.Windows)]
    public void Registry_ReadsExpectedValue()
    {
        var value = Microsoft.Win32.Registry.GetValue(
            @"HKEY_LOCAL_MACHINE\SOFTWARE\Microsoft\.NETFramework",
            "InstallRoot", null);
        Assert.IsNotNull(value);
    }

    // 2. Skip in CI (requires local GPU)
    [TestMethod]
    [CICondition(ConditionMode.Exclude)]
    public void RenderFrame_UsesGpuAcceleration()
    {
        var renderer = new GpuRenderer();
        var frame = renderer.Render();
        Assert.IsNotNull(frame);
    }

    // 3. Flaky external API — retry up to 3 times
    [TestMethod]
    [Retry(3)]
    [Timeout(10000)]
    public async Task WeatherApi_ReturnsForecast()
    {
        var client = new WeatherClient();
        var forecast = await client.GetForecastAsync(
            _testContext.CancellationToken);
        Assert.IsNotNull(forecast);
    }

    // 4. Temp file cleanup — [TestCleanup] runs even on failure
    [TestMethod]
    public void Export_WritesToFile()
    {
        _tempFile = Path.GetTempFileName();
        var exporter = new DataExporter();

        exporter.Export(_tempFile);

        Assert.IsNotEmpty(File.ReadAllText(_tempFile));
    }

    [TestCleanup]
    public void Cleanup()
    {
        if (_tempFile is not null && File.Exists(_tempFile))
        {
            File.Delete(_tempFile);
        }
    }
}
```

**Summary of attributes used:**

| Scenario | Attribute/Pattern |
|----------|-------------------|
| Windows-only | `[OSCondition(OperatingSystems.Windows)]` |
| Skip in CI | `[CICondition(ConditionMode.Exclude)]` |
| Flaky API | `[Retry(3)]` |
| Cleanup on failure | `[TestCleanup]` method |

**Key notes:**
- `[OSCondition]` and `[CICondition]` require MSTest 3.10+
- `[Retry]` requires MSTest 3.9+ — use only for genuine external flakiness, not internal race conditions
- `[TestCleanup]` always runs after each test (pass or fail), making it ideal for resource cleanup
- Combine `[Retry]` with `[Timeout]` and `CancellationToken` to avoid hanging on retries
